class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        import math
        # sieve primes up to sqrt(r)
        limit = int(math.isqrt(r)) + 1
        sieve = list(range(limit + 1))
        for i in range(2, int(math.isqrt(limit)) + 1):
            if sieve[i] == i:
                j = i * i
                while j <= limit:
                    if sieve[j] == j:
                        sieve[j] = i
                    j += i
        count = 0
        for p in range(2, limit + 1):
            if sieve[p] == p:  # prime
                sq = p * p
                if l <= sq <= r:
                    count += 1
        return (r - l + 1) - count

